const pregunta = $('Loop Over Items2').item.json.Preguntas;

const ground_truth =
  $('Code for Groundtruth2').item.json.ground_truth || '';

let answer = '';

try {
  answer = $('HTTP Request to Agent2').item.json.output;
} catch (e) {
  answer = 'error obteniendo respuesta';
}

// contexts completos con metadata
const contexts = items
  .map(item => ({
    id: item.json.id,
    content: item.json.content,
    similarity: item.json.similarity,
    metadata: {
      source: item.json.metadata?.source,
      page: item.json.metadata?.page,
      line: item.json.metadata?.line,
      lines: item.json.metadata?.loc?.lines
    }
  }))
  .filter(c => c.content);

return [{
  json: {
    question: pregunta,
    answer,
    contexts,
    ground_truth
  }
}];

const r1 = $json["Respuestas Experto 1"];
const r2 = $json["Respuestas Experto 2"];
const r3 = $json["Respuestas Experto 3"];
const r4 = $json["Respuestas Experto 4"];
const r5 = $json["Respuestas Experto 5"];
const r6 = $json["Respuestas Experto 6"];

return [{
  json: {
    ground_truth:
      `${r1}\n\n${r2}\n\n${r3}\n\n${r4}\n\n${r5}\n\n${r6}`
  }
}];

const prev = $input.item.json;
let scores;

try {
  const raw = prev.output[0].content[0].text;
  const clean = raw.replace(/```json|```/g, '').trim();
  scores = JSON.parse(clean);
} catch(e) {
  scores = {
    faithfulness: 0, answer_relevancy: 0,
    context_precision: 0, context_recall: 0,
    flag: 'error', nota: 'no se pudo parsear'
  };
}

const ragas_score = parseFloat((
  (scores.faithfulness + scores.answer_relevancy +
   scores.context_precision + scores.context_recall) / 4
).toFixed(3));

return {
  json: {
    pregunta: $('Loop Over Items2').item.json.Preguntas,
    answer: $('Code PreguntaRespuesta2').item.json.answer,
    ground_truth: $('Code for Groundtruth2').item.json.ground_truth,
    faithfulness: scores.faithfulness,
    answer_relevancy: scores.answer_relevancy,
    context_precision: scores.context_precision,
    context_recall: scores.context_recall,
    ragas_score: ragas_score,
    flag: scores.flag,
    nota: scores.nota || ''
  }
};

